local b64 = ""
local decode = (crypt and crypt.base64decode) or base64_decode or (base64 and base64.decode) or (syn and syn.crypt and syn.crypt.base64 and syn.crypt.base64.decode)
if not decode then print("[HadoUI] no base64 decoder found on this executor") return end
if not isfolder("HadoUI") then makefolder("HadoUI") end
writefile("HadoUI/icon.png", decode(b64))
print("[HadoUI] icon installed: " .. #readfile("HadoUI/icon.png") .. " bytes | getcustomasset available: " .. tostring(getcustomasset ~= nil))